PRAGMA defer_foreign_keys=TRUE;
CREATE TABLE users (
  id TEXT PRIMARY KEY,
  email TEXT UNIQUE NOT NULL,
  password_hash TEXT NOT NULL,
  role TEXT NOT NULL DEFAULT 'subcontractor',
  first_name TEXT,
  last_name TEXT,
  company_name TEXT,
  phone TEXT,
  lang TEXT DEFAULT 'fr',
  is_active INTEGER DEFAULT 1,
  invite_token TEXT,
  invite_expires_at TEXT,
  created_at TEXT DEFAULT (datetime('now')),
  updated_at TEXT DEFAULT (datetime('now'))
, company_id TEXT REFERENCES companies(id) ON DELETE SET NULL, user_type TEXT DEFAULT 'subcontractor', access_level TEXT NOT NULL DEFAULT 'editeur');
CREATE TABLE refresh_tokens (
  id TEXT PRIMARY KEY,
  user_id TEXT NOT NULL REFERENCES users(id) ON DELETE CASCADE,
  token_hash TEXT NOT NULL,
  expires_at TEXT NOT NULL,
  created_at TEXT DEFAULT (datetime('now'))
);
CREATE TABLE projects (
  id TEXT PRIMARY KEY,
  name TEXT NOT NULL,
  reference TEXT,
  address TEXT,
  city TEXT,
  postal_code TEXT,
  client_name TEXT,
  client_email TEXT,
  client_phone TEXT,
  description TEXT,
  start_date TEXT,
  duration_weeks INTEGER,
  budget_ht REAL,
  status TEXT DEFAULT 'draft',
  ai_prompt TEXT,
  created_by TEXT REFERENCES users(id),
  created_at TEXT DEFAULT (datetime('now')),
  updated_at TEXT DEFAULT (datetime('now'))
, company_id TEXT REFERENCES companies(id) ON DELETE SET NULL, lot_types TEXT DEFAULT NULL, meeting_time TEXT DEFAULT NULL, client_id TEXT REFERENCES clients(id), parent_project_id TEXT REFERENCES projects(id) ON DELETE SET NULL, project_type TEXT NOT NULL DEFAULT 'standalone');
CREATE TABLE lots (
  id TEXT PRIMARY KEY,
  project_id TEXT NOT NULL REFERENCES projects(id) ON DELETE CASCADE,
  code TEXT NOT NULL,
  name TEXT NOT NULL,
  name_tr TEXT,
  duration_days INTEGER NOT NULL DEFAULT 10,
  start_date_planned TEXT,
  end_date_planned TEXT,
  start_date_actual TEXT,
  end_date_actual TEXT,
  progress_percent INTEGER DEFAULT 0,
  status TEXT DEFAULT 'pending',
  subcontractor_id TEXT REFERENCES users(id),
  color TEXT DEFAULT '#6B7280',
  zone TEXT,
  notes TEXT,
  is_critical INTEGER DEFAULT 0,
  early_start INTEGER DEFAULT 0,
  early_finish INTEGER DEFAULT 0,
  late_start INTEGER DEFAULT 0,
  late_finish INTEGER DEFAULT 0,
  total_float INTEGER DEFAULT 0,
  sort_order INTEGER DEFAULT 0,
  created_at TEXT DEFAULT (datetime('now')),
  updated_at TEXT DEFAULT (datetime('now'))
, market_deadline TEXT, is_provisional INTEGER DEFAULT 0, parent_lot_id TEXT REFERENCES lots(id) ON DELETE SET NULL, team_id TEXT REFERENCES teams(id) ON DELETE SET NULL);
CREATE TABLE dependencies (
  id TEXT PRIMARY KEY,
  project_id TEXT NOT NULL REFERENCES projects(id) ON DELETE CASCADE,
  predecessor_id TEXT NOT NULL REFERENCES lots(id) ON DELETE CASCADE,
  successor_id TEXT NOT NULL REFERENCES lots(id) ON DELETE CASCADE,
  type TEXT DEFAULT 'FS',
  lag_days INTEGER DEFAULT 0,
  UNIQUE(predecessor_id, successor_id)
);
CREATE TABLE progress_updates (
  id TEXT PRIMARY KEY,
  lot_id TEXT NOT NULL REFERENCES lots(id) ON DELETE CASCADE,
  user_id TEXT NOT NULL REFERENCES users(id),
  progress_percent INTEGER NOT NULL,
  comment TEXT,
  created_at TEXT DEFAULT (datetime('now'))
);
CREATE TABLE notifications (
  id TEXT PRIMARY KEY,
  user_id TEXT NOT NULL REFERENCES users(id) ON DELETE CASCADE,
  project_id TEXT REFERENCES projects(id),
  lot_id TEXT REFERENCES lots(id),
  type TEXT NOT NULL,
  title TEXT NOT NULL,
  title_tr TEXT,
  message TEXT NOT NULL,
  message_tr TEXT,
  is_read INTEGER DEFAULT 0,
  created_at TEXT DEFAULT (datetime('now'))
);
CREATE TABLE ai_sessions (
  id TEXT PRIMARY KEY,
  project_id TEXT REFERENCES projects(id) ON DELETE CASCADE,
  prompt TEXT,
  response TEXT,
  created_at TEXT DEFAULT (datetime('now'))
);
CREATE TABLE companies (
  id           TEXT PRIMARY KEY,
  name         TEXT NOT NULL,
  siret        TEXT,
  address      TEXT,
  city         TEXT,
  postal_code  TEXT,
  email        TEXT,
  phone        TEXT,
  plan         TEXT NOT NULL DEFAULT 'free',  -- free | pro | enterprise
  plan_expires_at TEXT,                        -- date ISO, NULL = pas d'expiration
  is_active    INTEGER NOT NULL DEFAULT 1,
  created_at   TEXT NOT NULL DEFAULT (datetime('now')),
  updated_at   TEXT NOT NULL DEFAULT (datetime('now'))
, type TEXT NOT NULL DEFAULT 'entreprise_generale', activity TEXT, lot_types TEXT);
CREATE TABLE milestones (
  id TEXT PRIMARY KEY,
  project_id TEXT NOT NULL REFERENCES projects(id) ON DELETE CASCADE,
  name TEXT NOT NULL,
  date TEXT NOT NULL,
  color TEXT NOT NULL DEFAULT '#ef4444',
  created_at TEXT DEFAULT (datetime('now'))
);
CREATE TABLE password_reset_tokens (
  id TEXT PRIMARY KEY,
  user_id TEXT NOT NULL REFERENCES users(id) ON DELETE CASCADE,
  token_hash TEXT NOT NULL,
  expires_at TEXT NOT NULL,
  used INTEGER DEFAULT 0,
  created_at TEXT DEFAULT (datetime('now'))
);
CREATE TABLE lot_tasks (
  id TEXT PRIMARY KEY,
  lot_id TEXT NOT NULL REFERENCES lots(id) ON DELETE CASCADE,
  name TEXT NOT NULL,
  type TEXT NOT NULL DEFAULT 'custom',  -- 'commande'|'execution'|'livraison'|'custom'
  start_date TEXT,
  end_date TEXT,
  progress INTEGER DEFAULT 0,
  subcontractor_id TEXT REFERENCES users(id),
  sort_order INTEGER DEFAULT 0,
  created_at TEXT DEFAULT (datetime('now'))
);
CREATE TABLE lot_assignments (
  id TEXT PRIMARY KEY,
  lot_id TEXT NOT NULL REFERENCES lots(id) ON DELETE CASCADE,
  subcontractor_id TEXT NOT NULL REFERENCES users(id) ON DELETE CASCADE,
  start_date TEXT,
  end_date TEXT,
  progress INTEGER DEFAULT 0,
  comment TEXT,
  created_at TEXT DEFAULT (datetime('now')),
  UNIQUE(lot_id, subcontractor_id)
);
CREATE TABLE teams (
  id TEXT PRIMARY KEY,
  name TEXT NOT NULL,
  color TEXT NOT NULL DEFAULT '#6B7280',
  leader_id TEXT REFERENCES users(id) ON DELETE SET NULL,
  description TEXT,
  created_at TEXT DEFAULT (datetime('now')),
  updated_at TEXT DEFAULT (datetime('now'))
, company_id TEXT REFERENCES companies(id));
CREATE TABLE team_members (
  id TEXT PRIMARY KEY,
  team_id TEXT NOT NULL REFERENCES teams(id) ON DELETE CASCADE,
  user_id TEXT NOT NULL REFERENCES users(id) ON DELETE CASCADE,
  role_in_team TEXT DEFAULT 'member',
  created_at TEXT DEFAULT (datetime('now')),
  UNIQUE(team_id, user_id)
);
CREATE TABLE clients (
  id          TEXT PRIMARY KEY,
  name        TEXT NOT NULL,
  email       TEXT,
  phone       TEXT,
  address     TEXT,
  city        TEXT,
  postal_code TEXT,
  notes       TEXT,
  created_at  TEXT DEFAULT (datetime('now')),
  updated_at  TEXT DEFAULT (datetime('now'))
, company_id TEXT REFERENCES companies(id));
CREATE TABLE lot_templates (
  id            TEXT PRIMARY KEY,
  catalog_type  TEXT NOT NULL DEFAULT 'btp',  -- 'btp' | 'facade'
  code          TEXT NOT NULL,
  name          TEXT NOT NULL,
  name_tr       TEXT,
  duration_days INTEGER NOT NULL DEFAULT 10,
  color         TEXT NOT NULL DEFAULT '#6B7280',
  zone          TEXT,
  sort_order    INTEGER NOT NULL DEFAULT 0,
  lot_types     TEXT,         -- JSON array ['ITE','ECHAF'...] filtrage facade
  parent_code   TEXT,         -- sous-lot facade
  created_at    TEXT DEFAULT (datetime('now')),
  updated_at    TEXT DEFAULT (datetime('now')),
  UNIQUE(catalog_type, code)
);
CREATE TABLE lot_template_deps (
  id            TEXT PRIMARY KEY,
  catalog_type  TEXT NOT NULL DEFAULT 'btp',
  pred_code     TEXT NOT NULL,
  succ_code     TEXT NOT NULL,
  dep_type      TEXT NOT NULL DEFAULT 'FS',
  lag_days      INTEGER NOT NULL DEFAULT 0,
  created_at    TEXT DEFAULT (datetime('now')),
  UNIQUE(catalog_type, pred_code, succ_code)
);
CREATE TABLE platform_menu_config (
  id         TEXT PRIMARY KEY,
  key        TEXT NOT NULL UNIQUE,
  label_fr   TEXT NOT NULL,
  label_tr   TEXT,
  sort_order INTEGER NOT NULL DEFAULT 0,
  is_visible INTEGER NOT NULL DEFAULT 1,
  icon_name  TEXT,
  created_at TEXT DEFAULT (datetime('now')),
  updated_at TEXT DEFAULT (datetime('now'))
);
CREATE INDEX idx_lots_project ON lots(project_id);
CREATE INDEX idx_deps_project ON dependencies(project_id);
CREATE INDEX idx_notifs_user ON notifications(user_id, is_read);
CREATE INDEX idx_refresh_user ON refresh_tokens(user_id);
CREATE INDEX idx_users_company ON users(company_id);
CREATE INDEX idx_projects_company ON projects(company_id);
